        public static void CreateFilter(DirectoryFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* ОдиницяВиміру, pointer */
                Switch sw = Switch.New();
                ПакуванняОдиниціВиміру_PointerControl ОдиницяВиміру = ПакуванняОдиниціВиміру_PointerControl.New();
                        ОдиницяВиміру.Caption = "";
                        ОдиницяВиміру.AfterSelectFunc = () => sw.Active = true;
                        object get() => ОдиницяВиміру.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(Номенклатура_Const.ОдиницяВиміру, get, sw));
                form.Filter.Append("Пакування:", ОдиницяВиміру, sw);
            }
            
            { /* ТипНоменклатури, enum */
                Switch sw = Switch.New();
                
                        ComboBoxText ТипНоменклатури = ComboBoxText.New();
                        ТипНоменклатури.MarginStart = 5;
                        foreach (var item in ПсевдонімиПерелічення.ТипиНоменклатури_List())
                            ТипНоменклатури.Append(item.Value.ToString(), item.Name);
                        ТипНоменклатури.Active = 0;
                        object get() => Enum.TryParse(ТипНоменклатури.ActiveId, out ТипиНоменклатури value) ? (int)value: 0;
                    
                filterList.Add(new(Номенклатура_Const.ТипНоменклатури, get, sw));
                form.Filter.Append("Тип:", ТипНоменклатури, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DirectoryFormJournalBase form)
        {
            
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Довідники.Номенклатура_Select Номенклатура_Select = new();
            Номенклатура_Select.QuerySelect.Field.AddRange(
                [
