        public static void CreateFilter(DirectoryFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Кількісний, boolean */
                Switch sw = Switch.New();
                
                        CheckButton Кількісний = CheckButton.New();
                        Кількісний.OnActivate += (_, _) => sw.Active = Кількісний.Active;
                        object get() => Кількісний.Active;
                    
                filterList.Add(new(ПланРахунків_Const.Кількісний, get, sw));
                form.Filter.Append("Кількісний:", Кількісний, sw);
            }
            
            { /* Сумовий, boolean */
                Switch sw = Switch.New();
                
                        CheckButton Сумовий = CheckButton.New();
                        Сумовий.OnActivate += (_, _) => sw.Active = Сумовий.Active;
                        object get() => Сумовий.Active;
                    
                filterList.Add(new(ПланРахунків_Const.Сумовий, get, sw));
                form.Filter.Append("Сумовий:", Сумовий, sw);
            }
            
            { /* Валютний, boolean */
                Switch sw = Switch.New();
                
                        CheckButton Валютний = CheckButton.New();
                        Валютний.OnActivate += (_, _) => sw.Active = Валютний.Active;
                        object get() => Валютний.Active;
                    
                filterList.Add(new(ПланРахунків_Const.Валютний, get, sw));
                form.Filter.Append("Валютний:", Валютний, sw);
            }
            
            { /* Забалансовий, boolean */
                Switch sw = Switch.New();
                
                        CheckButton Забалансовий = CheckButton.New();
                        Забалансовий.OnActivate += (_, _) => sw.Active = Забалансовий.Active;
                        object get() => Забалансовий.Active;
                    
                filterList.Add(new(ПланРахунків_Const.Забалансовий, get, sw));
                form.Filter.Append("Забалансовий:", Забалансовий, sw);
            }
            
            { /* Субконто1, string */
                Switch sw = Switch.New();
                
                        Entry Субконто1 = Entry.New();
                        Субконто1.WidthRequest = 300;
                        object get() => Субконто1.GetText();
                    
                filterList.Add(new(ПланРахунків_Const.Субконто1, get, sw));
                form.Filter.Append("Субконто 1:", Субконто1, sw);
            }
            
            { /* Субконто2, string */
                Switch sw = Switch.New();
                
                        Entry Субконто2 = Entry.New();
                        Субконто2.WidthRequest = 300;
                        object get() => Субконто2.GetText();
                    
                filterList.Add(new(ПланРахунків_Const.Субконто2, get, sw));
                form.Filter.Append("Субконто 2:", Субконто2, sw);
            }
            
            { /* Субконто3, string */
                Switch sw = Switch.New();
                
                        Entry Субконто3 = Entry.New();
                        Субконто3.WidthRequest = 300;
                        object get() => Субконто3.GetText();
                    
                filterList.Add(new(ПланРахунків_Const.Субконто3, get, sw));
                form.Filter.Append("Субконто 3:", Субконто3, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

