        public static async Task<List<DirectoryHierarchicalRow>> LoadChildren(DirectoryFormJournalBase form, UniqueID[] parents)
        {
            /* Вибірка */
            Довідники.ПланРахунків_Select ПланРахунків_Select = new();
            ПланРахунків_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + parent */ Довідники.ПланРахунків_Const.Родич,
                        /* + isfolders */ Довідники.ПланРахунків_Const.ЦеГрупа,
                        /*Клас*/ Довідники.ПланРахунків_Const.Клас,
                    /*Код*/ Довідники.ПланРахунків_Const.Код,
                    /*Назва*/ Довідники.ПланРахунків_Const.Назва,
                    /*Кількісний*/ Довідники.ПланРахунків_Const.Кількісний,
                    /*Сумовий*/ Довідники.ПланРахунків_Const.Сумовий,
                    /*Валютний*/ Довідники.ПланРахунків_Const.Валютний,
                    /*Забалансовий*/ Довідники.ПланРахунків_Const.Забалансовий,
                    /*Субконто1*/ Довідники.ПланРахунків_Const.Субконто1,
                    /*Субконто2*/ Довідники.ПланРахунків_Const.Субконто2,
                    /*Субконто3*/ Довідники.ПланРахунків_Const.Субконто3,
                    
                ]);
            
                    /* Сортування */
                    ПланРахунків_Select.QuerySelect.Order.Add(Довідники.ПланРахунків_Const.Клас, SelectOrder.ASC);
                
                    /* Сортування */
                    ПланРахунків_Select.QuerySelect.Order.Add(Довідники.ПланРахунків_Const.Код, SelectOrder.ASC);
                

            /* Відбір по полю Родич */
            ПланРахунків_Select.QuerySelect.Where.Add(new(Довідники.ПланРахунків_Const.Родич, Comparison.IN, $"'{string.Join("', '", parents.Select(x => x.UGuid))}'", true));

            /* Сховати відкриту папку для вибору */
            if (form.OpenFolder != null)
                ПланРахунків_Select.QuerySelect.Where.Add(new("uid", Comparison.NOT, form.OpenFolder.UGuid));
            
            
            await ПланРахунків_Select.Select();
            List<DirectoryHierarchicalRow> list = new(ПланРахунків_Select.Count());
            while (ПланРахунків_Select.MoveNext())
            {
                Довідники.ПланРахунків_Pointer? curr = ПланРахунків_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryHierarchicalRow row = DirectoryHierarchicalRow.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Parent = new UniqueID(Fields[Довідники.ПланРахунків_Const.Родич]);
                    row.Fields.Add("Клас", Fields[Довідники.ПланРахунків_Const.Клас].ToString() ?? "");
                    row.Fields.Add("Код", Fields[Довідники.ПланРахунків_Const.Код].ToString() ?? "");
                    row.Fields.Add("Назва", Fields[Довідники.ПланРахунків_Const.Назва].ToString() ?? "");
                    row.Fields.Add("Кількісний", (Fields[Довідники.ПланРахунків_Const.Кількісний] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Кількісний]) ? "Так" : "");
                    row.Fields.Add("Сумовий", (Fields[Довідники.ПланРахунків_Const.Сумовий] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Сумовий]) ? "Так" : "");
                    row.Fields.Add("Валютний", (Fields[Довідники.ПланРахунків_Const.Валютний] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Валютний]) ? "Так" : "");
                    row.Fields.Add("Забалансовий", (Fields[Довідники.ПланРахунків_Const.Забалансовий] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Забалансовий]) ? "Так" : "");
                    row.Fields.Add("Субконто1", Fields[Довідники.ПланРахунків_Const.Субконто1].ToString() ?? "");
                    row.Fields.Add("Субконто2", Fields[Довідники.ПланРахунків_Const.Субконто2].ToString() ?? "");
                    row.Fields.Add("Субконто3", Fields[Довідники.ПланРахунків_Const.Субконто3].ToString() ?? "");
                    
                    row.AllowedContent = AllowedContent;
                    
                    row.IsFolder = (bool)Fields[Довідники.ПланРахунків_Const.ЦеГрупа];
                    
                    list.Add(row);
                }
            }

            return list;
        }
        

        public static async Task LoadRecords(DirectoryFormJournalBase form)
        {
            form.BeforeLoadRecords();

            //Вибраний елемент
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DirectoryPointerItem;

            /* Вибірка */
            Довідники.ПланРахунків_Select ПланРахунків_Select = new();
            ПланРахунків_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + isfolders */ Довідники.ПланРахунків_Const.ЦеГрупа,
                        /*Клас*/ Довідники.ПланРахунків_Const.Клас,
                    /*Код*/ Довідники.ПланРахунків_Const.Код,
                    /*Назва*/ Довідники.ПланРахунків_Const.Назва,
                    /*Кількісний*/ Довідники.ПланРахунків_Const.Кількісний,
                    /*Сумовий*/ Довідники.ПланРахунків_Const.Сумовий,
                    /*Валютний*/ Довідники.ПланРахунків_Const.Валютний,
                    /*Забалансовий*/ Довідники.ПланРахунків_Const.Забалансовий,
                    /*Субконто1*/ Довідники.ПланРахунків_Const.Субконто1,
                    /*Субконто2*/ Довідники.ПланРахунків_Const.Субконто2,
                    /*Субконто3*/ Довідники.ПланРахунків_Const.Субконто3,
                    
                ]);
            
                    /* Сортування */
                    ПланРахунків_Select.QuerySelect.Order.Add(Довідники.ПланРахунків_Const.Клас, SelectOrder.ASC);
                
                    /* Сортування */
                    ПланРахунків_Select.QuerySelect.Order.Add(Довідники.ПланРахунків_Const.Код, SelectOrder.ASC);
                

            /* Відбори */
            if (form.WhereList != null) ПланРахунків_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Додатковий відбір Parent */
            if (form.ParentWhereList != null && !form.IsUseHierarchy() && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                ПланРахунків_Select.QuerySelect.Where.AddRange(form.ParentWhereList);

            
            /* Сховати відкриту папку для вибору */
            if (form.OpenFolder != null)
                ПланРахунків_Select.QuerySelect.Where.Add(new("uid", Comparison.NOT, form.OpenFolder.UGuid));

            /* Тільки елементи верхнього рівня для стандартного виводу */
            if (form.WhereList == null && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                ПланРахунків_Select.QuerySelect.Where.Add(new(Довідники.ПланРахунків_Const.Родич, Comparison.EQ, Guid.Empty));

                
            await ПланРахунків_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();

            
            /* Пустий рядок */
            if (form.InsertEmptyFirstRow)
                form.Store.Append(LoadEmptyChildren(form));
            

            while (ПланРахунків_Select.MoveNext())
            {
                Довідники.ПланРахунків_Pointer? curr = ПланРахунків_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryHierarchicalRow row = DirectoryHierarchicalRow.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Fields.Add("Клас", Fields[Довідники.ПланРахунків_Const.Клас].ToString() ?? "");
                    row.Fields.Add("Код", Fields[Довідники.ПланРахунків_Const.Код].ToString() ?? "");
                    row.Fields.Add("Назва", Fields[Довідники.ПланРахунків_Const.Назва].ToString() ?? "");
                    row.Fields.Add("Кількісний", (Fields[Довідники.ПланРахунків_Const.Кількісний] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Кількісний]) ? "Так" : "");
                    row.Fields.Add("Сумовий", (Fields[Довідники.ПланРахунків_Const.Сумовий] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Сумовий]) ? "Так" : "");
                    row.Fields.Add("Валютний", (Fields[Довідники.ПланРахунків_Const.Валютний] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Валютний]) ? "Так" : "");
                    row.Fields.Add("Забалансовий", (Fields[Довідники.ПланРахунків_Const.Забалансовий] != DBNull.Value && (bool)Fields[Довідники.ПланРахунків_Const.Забалансовий]) ? "Так" : "");
                    row.Fields.Add("Субконто1", Fields[Довідники.ПланРахунків_Const.Субконто1].ToString() ?? "");
                    row.Fields.Add("Субконто2", Fields[Довідники.ПланРахунків_Const.Субконто2].ToString() ?? "");
                    row.Fields.Add("Субконто3", Fields[Довідники.ПланРахунків_Const.Субконто3].ToString() ?? "");
                    
                    row.AllowedContent = AllowedContent;
                    
                    row.IsFolder = (bool)Fields[Довідники.ПланРахунків_Const.ЦеГрупа];
                    
                    form.Store.Append(row);
                        
                }
            }
            
            /* Вибірка всіх родичів для вибраного елементу */
            List<UniqueID> parents = [];
            if (unigueIDSelect != null && !unigueIDSelect.IsEmpty())
            {
                ПланРахунків_SelectHierarchical selectParents = new();
                selectParents.QuerySelect.ParentUid = unigueIDSelect;
                selectParents.QuerySelect.Reverse = true;
                await selectParents.Select();
                while (selectParents.MoveNext())
                {
                    Довідники.ПланРахунків_Pointer? curr = selectParents.Current;
                    if (curr != null) parents.Add(curr.UniqueID);
                }                        
                parents.Reverse();
            }
            await form.AfterLoadRecords(parents, unigueIDSelect);
                
        }
    }
        
