        public static async Task<List<DirectoryHierarchicalRow>> LoadChildren(DirectoryFormJournalBase form, UniqueID[] parents)
        {
            /* Вибірка */
            Довідники.Категорії_Select Категорії_Select = new();
            Категорії_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + parent */ Довідники.Категорії_Const.Родич,
                        /*Код*/ Довідники.Категорії_Const.Код,
                    /*Назва*/ Довідники.Категорії_Const.Назва,
                    /*МетодСписання*/ Довідники.Категорії_Const.МетодСписання,
                    
                ]);
            
                    /* Сортування */
                    Категорії_Select.QuerySelect.Order.Add(Довідники.Категорії_Const.Назва, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.ПланРахунків_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.РахунокОбліку,
                            Категорії_Select.QuerySelect.Table, "join_tab_1", "РахунокОбліку");
                        
                            /* Приєднання pointer */
                            Довідники.ПланРахунків_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.РахунокДоходів,
                            Категорії_Select.QuerySelect.Table, "join_tab_2", "РахунокДоходів");
                        
                            /* Приєднання pointer */
                            Довідники.Статті_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.СтаттяДоходів,
                            Категорії_Select.QuerySelect.Table, "join_tab_3", "СтаттяДоходів");
                        
                            /* Приєднання pointer */
                            Довідники.ПланРахунків_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.РахунокВитрат,
                            Категорії_Select.QuerySelect.Table, "join_tab_4", "РахунокВитрат");
                        
                            /* Приєднання pointer */
                            Довідники.Статті_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.СтаттяВитрат,
                            Категорії_Select.QuerySelect.Table, "join_tab_5", "СтаттяВитрат");
                        

            /* Відбір по полю Родич */
            Категорії_Select.QuerySelect.Where.Add(new(Довідники.Категорії_Const.Родич, Comparison.IN, $"'{string.Join("', '", parents.Select(x => x.UGuid))}'", true));

            /* Сховати відкриту папку для вибору */
            if (form.OpenFolder != null)
                Категорії_Select.QuerySelect.Where.Add(new("uid", Comparison.NOT, form.OpenFolder.UGuid));
            
            
            await Категорії_Select.Select();
            List<DirectoryHierarchicalRow> list = new(Категорії_Select.Count());
            while (Категорії_Select.MoveNext())
            {
                Довідники.Категорії_Pointer? curr = Категорії_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryHierarchicalRow row = DirectoryHierarchicalRow.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Parent = new UniqueID(Fields[Довідники.Категорії_Const.Родич]);
                    row.Fields.Add("Код", Fields[Довідники.Категорії_Const.Код].ToString() ?? "");
                    row.Fields.Add("Назва", Fields[Довідники.Категорії_Const.Назва].ToString() ?? "");
                    row.Fields.Add("МетодСписання", Перелічення.ПсевдонімиПерелічення.МетодиСписання_Alias((Перелічення.МетодиСписання)(Fields[Довідники.Категорії_Const.МетодСписання] != DBNull.Value ? Fields[Довідники.Категорії_Const.МетодСписання] : 0) ));
                    row.Fields.Add("РахунокОбліку", Fields["РахунокОбліку"].ToString() ?? "");
                    row.Fields.Add("РахунокДоходів", Fields["РахунокДоходів"].ToString() ?? "");
                    row.Fields.Add("СтаттяДоходів", Fields["СтаттяДоходів"].ToString() ?? "");
                    row.Fields.Add("РахунокВитрат", Fields["РахунокВитрат"].ToString() ?? "");
                    row.Fields.Add("СтаттяВитрат", Fields["СтаттяВитрат"].ToString() ?? "");
                    
                    row.AllowedContent = AllowedContent;
                    
                    list.Add(row);
                }
            }

            return list;
        }
        

        public static async Task LoadRecords(DirectoryFormJournalBase form)
        {
            form.BeforeLoadRecords();

            //Вибраний елемент
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DirectoryPointerItem;

            /* Вибірка */
            Довідники.Категорії_Select Категорії_Select = new();
            Категорії_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /*Код*/ Довідники.Категорії_Const.Код,
                    /*Назва*/ Довідники.Категорії_Const.Назва,
                    /*МетодСписання*/ Довідники.Категорії_Const.МетодСписання,
                    
                ]);
            
                    /* Сортування */
                    Категорії_Select.QuerySelect.Order.Add(Довідники.Категорії_Const.Назва, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.ПланРахунків_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.РахунокОбліку,
                            Категорії_Select.QuerySelect.Table, "join_tab_1", "РахунокОбліку");
                        
                            /* Приєднання pointer */
                            Довідники.ПланРахунків_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.РахунокДоходів,
                            Категорії_Select.QuerySelect.Table, "join_tab_2", "РахунокДоходів");
                        
                            /* Приєднання pointer */
                            Довідники.Статті_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.СтаттяДоходів,
                            Категорії_Select.QuerySelect.Table, "join_tab_3", "СтаттяДоходів");
                        
                            /* Приєднання pointer */
                            Довідники.ПланРахунків_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.РахунокВитрат,
                            Категорії_Select.QuerySelect.Table, "join_tab_4", "РахунокВитрат");
                        
                            /* Приєднання pointer */
                            Довідники.Статті_Pointer.GetJoin(Категорії_Select.QuerySelect, Довідники.Категорії_Const.СтаттяВитрат,
                            Категорії_Select.QuerySelect.Table, "join_tab_5", "СтаттяВитрат");
                        

            /* Відбори */
            if (form.WhereList != null) Категорії_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Додатковий відбір Parent */
            if (form.ParentWhereList != null && !form.IsUseHierarchy() && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                Категорії_Select.QuerySelect.Where.AddRange(form.ParentWhereList);

            
            /* Сховати відкриту папку для вибору */
            if (form.OpenFolder != null)
                Категорії_Select.QuerySelect.Where.Add(new("uid", Comparison.NOT, form.OpenFolder.UGuid));

            /* Тільки елементи верхнього рівня для стандартного виводу */
            if (form.WhereList == null && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                Категорії_Select.QuerySelect.Where.Add(new(Довідники.Категорії_Const.Родич, Comparison.EQ, Guid.Empty));

                
            await Категорії_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();

            
            /* Пустий рядок */
            if (form.InsertEmptyFirstRow)
                form.Store.Append(LoadEmptyChildren(form));
            

            while (Категорії_Select.MoveNext())
            {
                Довідники.Категорії_Pointer? curr = Категорії_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryHierarchicalRow row = DirectoryHierarchicalRow.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Fields.Add("Код", Fields[Довідники.Категорії_Const.Код].ToString() ?? "");
                    row.Fields.Add("Назва", Fields[Довідники.Категорії_Const.Назва].ToString() ?? "");
                    row.Fields.Add("МетодСписання", Перелічення.ПсевдонімиПерелічення.МетодиСписання_Alias((Перелічення.МетодиСписання)(Fields[Довідники.Категорії_Const.МетодСписання] != DBNull.Value ? Fields[Довідники.Категорії_Const.МетодСписання] : 0) ));
                    row.Fields.Add("РахунокОбліку", Fields["РахунокОбліку"].ToString() ?? "");
                    row.Fields.Add("РахунокДоходів", Fields["РахунокДоходів"].ToString() ?? "");
                    row.Fields.Add("СтаттяДоходів", Fields["СтаттяДоходів"].ToString() ?? "");
                    row.Fields.Add("РахунокВитрат", Fields["РахунокВитрат"].ToString() ?? "");
                    row.Fields.Add("СтаттяВитрат", Fields["СтаттяВитрат"].ToString() ?? "");
                    
                    row.AllowedContent = AllowedContent;
                    
                    form.Store.Append(row);
                        
                }
            }
            
            /* Вибірка всіх родичів для вибраного елементу */
            List<UniqueID> parents = [];
            if (unigueIDSelect != null && !unigueIDSelect.IsEmpty())
            {
                Категорії_SelectHierarchical selectParents = new();
                selectParents.QuerySelect.ParentUid = unigueIDSelect;
                selectParents.QuerySelect.Reverse = true;
                await selectParents.Select();
                while (selectParents.MoveNext())
                {
                    Довідники.Категорії_Pointer? curr = selectParents.Current;
                    if (curr != null) parents.Add(curr.UniqueID);
                }                        
                parents.Reverse();
            }
            await form.AfterLoadRecords(parents, unigueIDSelect);
                
        }
    }
        
