        public static async Task UpdateRecords(DirectoryFormJournalBase form)
        {
            
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Довідники.МалоцінніПредмети_Select МалоцінніПредмети_Select = new();
            МалоцінніПредмети_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /*Код*/ Довідники.МалоцінніПредмети_Const.Код,
                    /*Назва*/ Довідники.МалоцінніПредмети_Const.Назва,
                    
                ]);
            
                    /* Сортування */
                    МалоцінніПредмети_Select.QuerySelect.Order.Add(Довідники.МалоцінніПредмети_Const.Назва, SelectOrder.ASC);
                

            /* Відбори */
            МалоцінніПредмети_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await МалоцінніПредмети_Select.Select();
            while (МалоцінніПредмети_Select.MoveNext())
            {
                Довідники.МалоцінніПредмети_Pointer? curr = МалоцінніПредмети_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryRowJournal row = DirectoryRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Fields.Add("Код", Fields[МалоцінніПредмети_Const.Код].ToString() ?? "");
                    row.Fields.Add("Назва", Fields[МалоцінніПредмети_Const.Назва].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DirectoryRowJournal? item = (DirectoryRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
            
        }

        

