        public static async Task<List<DirectoryHierarchicalRow>> LoadChildren(DirectoryFormJournalBase form, UniqueID[] parents)
        {
            /* Вибірка */
            Довідники.НоменклатураВнутрішня_Папки_Select НоменклатураВнутрішня_Папки_Select = new();
            НоменклатураВнутрішня_Папки_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + parent */ Довідники.НоменклатураВнутрішня_Папки_Const.Родич,
                        /*Назва*/ Довідники.НоменклатураВнутрішня_Папки_Const.Назва,
                    
                ]);
            
                    /* Сортування */
                    НоменклатураВнутрішня_Папки_Select.QuerySelect.Order.Add(Довідники.НоменклатураВнутрішня_Папки_Const.Назва, SelectOrder.ASC);
                

            /* Відбір по полю Родич */
            НоменклатураВнутрішня_Папки_Select.QuerySelect.Where.Add(new(Довідники.НоменклатураВнутрішня_Папки_Const.Родич, Comparison.IN, $"'{string.Join("', '", parents.Select(x => x.UGuid))}'", true));

            /* Сховати відкриту папку для вибору */
            if (form.OpenFolder != null)
                НоменклатураВнутрішня_Папки_Select.QuerySelect.Where.Add(new("uid", Comparison.NOT, form.OpenFolder.UGuid));
            
            
            await НоменклатураВнутрішня_Папки_Select.Select();
            List<DirectoryHierarchicalRow> list = new(НоменклатураВнутрішня_Папки_Select.Count());
            while (НоменклатураВнутрішня_Папки_Select.MoveNext())
            {
                Довідники.НоменклатураВнутрішня_Папки_Pointer? curr = НоменклатураВнутрішня_Папки_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryHierarchicalRow row = DirectoryHierarchicalRow.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Parent = new UniqueID(Fields[Довідники.НоменклатураВнутрішня_Папки_Const.Родич]);
                    row.Fields.Add("Назва", Fields[Довідники.НоменклатураВнутрішня_Папки_Const.Назва].ToString() ?? "");
                    
                    row.AllowedContent = AllowedContent;
                    
                    list.Add(row);
                }
            }

            return list;
        }
        

        public static async Task LoadRecords(DirectoryFormJournalBase form)
        {
            form.BeforeLoadRecords();

            //Вибраний елемент
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DirectoryPointerItem;

            /* Вибірка */
            Довідники.НоменклатураВнутрішня_Папки_Select НоменклатураВнутрішня_Папки_Select = new();
            НоменклатураВнутрішня_Папки_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /*Назва*/ Довідники.НоменклатураВнутрішня_Папки_Const.Назва,
                    
                ]);
            
                    /* Сортування */
                    НоменклатураВнутрішня_Папки_Select.QuerySelect.Order.Add(Довідники.НоменклатураВнутрішня_Папки_Const.Назва, SelectOrder.ASC);
                

            /* Відбори */
            if (form.WhereList != null) НоменклатураВнутрішня_Папки_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Додатковий відбір Parent */
            if (form.ParentWhereList != null && !form.IsUseHierarchy() && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                НоменклатураВнутрішня_Папки_Select.QuerySelect.Where.AddRange(form.ParentWhereList);

            
            /* Сховати відкриту папку для вибору */
            if (form.OpenFolder != null)
                НоменклатураВнутрішня_Папки_Select.QuerySelect.Where.Add(new("uid", Comparison.NOT, form.OpenFolder.UGuid));

            /* Тільки елементи верхнього рівня для стандартного виводу */
            if (form.WhereList == null && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                НоменклатураВнутрішня_Папки_Select.QuerySelect.Where.Add(new(Довідники.НоменклатураВнутрішня_Папки_Const.Родич, Comparison.EQ, Guid.Empty));

                
            await НоменклатураВнутрішня_Папки_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();

            
            /* Пустий рядок */
            if (form.InsertEmptyFirstRow)
                form.Store.Append(LoadEmptyChildren(form));
            

            while (НоменклатураВнутрішня_Папки_Select.MoveNext())
            {
                Довідники.НоменклатураВнутрішня_Папки_Pointer? curr = НоменклатураВнутрішня_Папки_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryHierarchicalRow row = DirectoryHierarchicalRow.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Fields.Add("Назва", Fields[Довідники.НоменклатураВнутрішня_Папки_Const.Назва].ToString() ?? "");
                    
                    row.AllowedContent = AllowedContent;
                    
                    form.Store.Append(row);
                        
                }
            }
            
            /* Вибірка всіх родичів для вибраного елементу */
            List<UniqueID> parents = [];
            if (unigueIDSelect != null && !unigueIDSelect.IsEmpty())
            {
                НоменклатураВнутрішня_Папки_SelectHierarchical selectParents = new();
                selectParents.QuerySelect.ParentUid = unigueIDSelect;
                selectParents.QuerySelect.Reverse = true;
                await selectParents.Select();
                while (selectParents.MoveNext())
                {
                    Довідники.НоменклатураВнутрішня_Папки_Pointer? curr = selectParents.Current;
                    if (curr != null) parents.Add(curr.UniqueID);
                }                        
                parents.Reverse();
            }
            await form.AfterLoadRecords(parents, unigueIDSelect);
                
        }
    }
        
