            /* Відбори */
            if (form.WhereList != null) Бланки_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Додатковий відбір Parent */
            if (form.ParentWhereList != null && !form.IsUseHierarchy() && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                Бланки_Select.QuerySelect.Where.AddRange(form.ParentWhereList);

            
            /* Cторінки */
            await form.SplitPages(Бланки_Select.SplitSelectToPages, Бланки_Select.QuerySelect, unigueIDSelect);
            uint selectPosition = 0;
                
            await Бланки_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();

            

            while (Бланки_Select.MoveNext())
            {
                Довідники.Бланки_Pointer? curr = Бланки_Select.Current;
