        public static async Task UpdateRecords(DirectoryFormJournalBase form)
        {
            
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Довідники.ТипиБухОперацій_Select ТипиБухОперацій_Select = new();
            ТипиБухОперацій_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /*Код*/ Довідники.ТипиБухОперацій_Const.Код,
                    /*Назва*/ Довідники.ТипиБухОперацій_Const.Назва,
                    
                ]);
            
                    /* Сортування */
                    ТипиБухОперацій_Select.QuerySelect.Order.Add(Довідники.ТипиБухОперацій_Const.Назва, SelectOrder.ASC);
                

            /* Відбори */
            ТипиБухОперацій_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await ТипиБухОперацій_Select.Select();
            while (ТипиБухОперацій_Select.MoveNext())
            {
                Довідники.ТипиБухОперацій_Pointer? curr = ТипиБухОперацій_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryRowJournal row = DirectoryRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Fields.Add("Код", Fields[ТипиБухОперацій_Const.Код].ToString() ?? "");
                    row.Fields.Add("Назва", Fields[ТипиБухОперацій_Const.Назва].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DirectoryRowJournal? item = (DirectoryRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
            
        }

        

        public static async Task LoadRecords(DirectoryFormJournalBase form)
        {
            form.BeforeLoadRecords();

            //Вибраний елемент
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DirectoryPointerItem;

            /* Вибірка */
            Довідники.ТипиБухОперацій_Select ТипиБухОперацій_Select = new();
            ТипиБухОперацій_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /*Код*/ Довідники.ТипиБухОперацій_Const.Код,
                    /*Назва*/ Довідники.ТипиБухОперацій_Const.Назва,
                    
                ]);
            
                    /* Сортування */
                    ТипиБухОперацій_Select.QuerySelect.Order.Add(Довідники.ТипиБухОперацій_Const.Назва, SelectOrder.ASC);
                

            /* Відбори */
            if (form.WhereList != null) ТипиБухОперацій_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Додатковий відбір Parent */
            if (form.ParentWhereList != null && !form.IsUseHierarchy() && form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart)
                ТипиБухОперацій_Select.QuerySelect.Where.AddRange(form.ParentWhereList);

            
            /* Cторінки */
            await form.SplitPages(ТипиБухОперацій_Select.SplitSelectToPages, ТипиБухОперацій_Select.QuerySelect, unigueIDSelect);
            uint selectPosition = 0;
                
            await ТипиБухОперацій_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();

            

            while (ТипиБухОперацій_Select.MoveNext())
            {
                Довідники.ТипиБухОперацій_Pointer? curr = ТипиБухОперацій_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DirectoryRowJournal row = DirectoryRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Fields.Add("Код", Fields[Довідники.ТипиБухОперацій_Const.Код].ToString() ?? "");
                    row.Fields.Add("Назва", Fields[Довідники.ТипиБухОперацій_Const.Назва].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                        
                }
            }
            
            form.AfterLoadRecords(selectPosition);
                
        }
    }
        
    #endregion
    
}

