                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ЗамовленняПостачальнику_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ЗамовленняПостачальнику_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ЗамовленняПостачальнику_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Контрагент", Fields["Контрагент"].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("СумаДокументу", Fields[ЗамовленняПостачальнику_Const.СумаДокументу].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ЗамовленняПостачальнику_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.ЗамовленняПостачальнику_Select ЗамовленняПостачальнику_Select = new();
            ЗамовленняПостачальнику_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ЗамовленняПостачальнику_Const.Назва,
                    /*НомерДок*/ Документи.ЗамовленняПостачальнику_Const.НомерДок,
                    /*ДатаДок*/ Документи.ЗамовленняПостачальнику_Const.ДатаДок,
                    /*СумаДокументу*/ Документи.ЗамовленняПостачальнику_Const.СумаДокументу,
                    /*Коментар*/ Документи.ЗамовленняПостачальнику_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ЗамовленняПостачальнику_Select.QuerySelect.Order.Add(Документи.ЗамовленняПостачальнику_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ЗамовленняПостачальнику_Select.QuerySelect, Документи.ЗамовленняПостачальнику_Const.Організація,
                            ЗамовленняПостачальнику_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Контрагенти_Pointer.GetJoin(ЗамовленняПостачальнику_Select.QuerySelect, Документи.ЗамовленняПостачальнику_Const.Контрагент,
                            ЗамовленняПостачальнику_Select.QuerySelect.Table, "join_tab_2", "Контрагент");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ЗамовленняПостачальнику_Select.QuerySelect, Документи.ЗамовленняПостачальнику_Const.Склад,
                            ЗамовленняПостачальнику_Select.QuerySelect.Table, "join_tab_3", "Склад");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(ЗамовленняПостачальнику_Select.QuerySelect, Документи.ЗамовленняПостачальнику_Const.Валюта,
                            ЗамовленняПостачальнику_Select.QuerySelect.Table, "join_tab_4", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ЗамовленняПостачальнику_Select.QuerySelect, Документи.ЗамовленняПостачальнику_Const.Автор,
                            ЗамовленняПостачальнику_Select.QuerySelect.Table, "join_tab_5", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) ЗамовленняПостачальнику_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.ЗамовленняПостачальнику_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ЗамовленняПостачальнику_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ЗамовленняПостачальнику_Select.SplitSelectToPages, ЗамовленняПостачальнику_Select.QuerySelect, unigueIDSelect);

            
            await ЗамовленняПостачальнику_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (ЗамовленняПостачальнику_Select.MoveNext())
            {
                Документи.ЗамовленняПостачальнику_Pointer? curr = ЗамовленняПостачальнику_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ЗамовленняПостачальнику_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ЗамовленняПостачальнику_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ЗамовленняПостачальнику_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Контрагент", Fields["Контрагент"].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("СумаДокументу", Fields[ЗамовленняПостачальнику_Const.СумаДокументу].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ЗамовленняПостачальнику_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
