                column.Resizable = true;
                column.Expand = true;
                form.Grid.AppendColumn(column);
            }
  
        }

        public static void CreateFilter(DocumentFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Організація, pointer */
                Switch sw = Switch.New();
                Організації_PointerControl Організація = Організації_PointerControl.New();
                        Організація.Caption = "";
                        Організація.AfterSelectFunc = () => sw.Active = true;
                        object get() => Організація.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(РеалізаціяТоварівТаПослуг_Const.Організація, get, sw));
                form.Filter.Append("Організація:", Організація, sw);
            }
            
            { /* Контрагент, pointer */
                Switch sw = Switch.New();
                Контрагенти_PointerControl Контрагент = Контрагенти_PointerControl.New();
                        Контрагент.Caption = "";
                        Контрагент.AfterSelectFunc = () => sw.Active = true;
                        object get() => Контрагент.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(РеалізаціяТоварівТаПослуг_Const.Контрагент, get, sw));
                form.Filter.Append("Контрагент:", Контрагент, sw);
            }
            
            { /* Валюта, pointer */
                Switch sw = Switch.New();
                Валюти_PointerControl Валюта = Валюти_PointerControl.New();
                        Валюта.Caption = "";
                        Валюта.AfterSelectFunc = () => sw.Active = true;
                        object get() => Валюта.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(РеалізаціяТоварівТаПослуг_Const.Валюта, get, sw));
                form.Filter.Append("Валюта:", Валюта, sw);
            }
            
            { /* Каса, pointer */
                Switch sw = Switch.New();
                Каси_PointerControl Каса = Каси_PointerControl.New();
                        Каса.Caption = "";
                        Каса.AfterSelectFunc = () => sw.Active = true;
                        object get() => Каса.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(РеалізаціяТоварівТаПослуг_Const.Каса, get, sw));
                form.Filter.Append("Каса:", Каса, sw);
            }
            
            { /* Склад, pointer */
                Switch sw = Switch.New();
                Склади_PointerControl Склад = Склади_PointerControl.New();
                        Склад.Caption = "";
                        Склад.AfterSelectFunc = () => sw.Active = true;
                        object get() => Склад.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(РеалізаціяТоварівТаПослуг_Const.Склад, get, sw));
                form.Filter.Append("Склад:", Склад, sw);
            }
            
            { /* СумаДокументу, numeric */
                Switch sw = Switch.New();
                
                        NumericControl СумаДокументу = NumericControl.New();
                        object get() => СумаДокументу.Value;
                    
                filterList.Add(new(РеалізаціяТоварівТаПослуг_Const.СумаДокументу, get, sw));
                form.Filter.Append("Сума:", СумаДокументу, sw);
            }
            
            { /* Автор, pointer */
                Switch sw = Switch.New();
                Користувачі_PointerControl Автор = Користувачі_PointerControl.New();
                        Автор.Caption = "";
                        Автор.AfterSelectFunc = () => sw.Active = true;
                        object get() => Автор.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(РеалізаціяТоварівТаПослуг_Const.Автор, get, sw));
                form.Filter.Append("Автор:", Автор, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DocumentFormJournalBase form)
        {
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Документи.РеалізаціяТоварівТаПослуг_Select РеалізаціяТоварівТаПослуг_Select = new();
            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.РеалізаціяТоварівТаПослуг_Const.Назва,
                    /*НомерДок*/ Документи.РеалізаціяТоварівТаПослуг_Const.НомерДок,
                    /*ДатаДок*/ Документи.РеалізаціяТоварівТаПослуг_Const.ДатаДок,
                    /*СумаДокументу*/ Документи.РеалізаціяТоварівТаПослуг_Const.СумаДокументу,
                    /*Коментар*/ Документи.РеалізаціяТоварівТаПослуг_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    РеалізаціяТоварівТаПослуг_Select.QuerySelect.Order.Add(Документи.РеалізаціяТоварівТаПослуг_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Організація,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Контрагенти_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Контрагент,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_2", "Контрагент");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Валюта,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_3", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.Каси_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Каса,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_4", "Каса");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Склад,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_5", "Склад");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Автор,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_6", "Автор");
                        

            /* Відбори */
            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await РеалізаціяТоварівТаПослуг_Select.Select();
            while (РеалізаціяТоварівТаПослуг_Select.MoveNext())
            {
                Документи.РеалізаціяТоварівТаПослуг_Pointer? curr = РеалізаціяТоварівТаПослуг_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[РеалізаціяТоварівТаПослуг_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[РеалізаціяТоварівТаПослуг_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[РеалізаціяТоварівТаПослуг_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Контрагент", Fields["Контрагент"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("Каса", Fields["Каса"].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("СумаДокументу", Fields[РеалізаціяТоварівТаПослуг_Const.СумаДокументу].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[РеалізаціяТоварівТаПослуг_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.РеалізаціяТоварівТаПослуг_Select РеалізаціяТоварівТаПослуг_Select = new();
            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.РеалізаціяТоварівТаПослуг_Const.Назва,
                    /*НомерДок*/ Документи.РеалізаціяТоварівТаПослуг_Const.НомерДок,
                    /*ДатаДок*/ Документи.РеалізаціяТоварівТаПослуг_Const.ДатаДок,
                    /*СумаДокументу*/ Документи.РеалізаціяТоварівТаПослуг_Const.СумаДокументу,
                    /*Коментар*/ Документи.РеалізаціяТоварівТаПослуг_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    РеалізаціяТоварівТаПослуг_Select.QuerySelect.Order.Add(Документи.РеалізаціяТоварівТаПослуг_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Організація,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Контрагенти_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Контрагент,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_2", "Контрагент");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Валюта,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_3", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.Каси_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Каса,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_4", "Каса");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Склад,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_5", "Склад");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(РеалізаціяТоварівТаПослуг_Select.QuerySelect, Документи.РеалізаціяТоварівТаПослуг_Const.Автор,
                            РеалізаціяТоварівТаПослуг_Select.QuerySelect.Table, "join_tab_6", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) РеалізаціяТоварівТаПослуг_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.РеалізаціяТоварівТаПослуг_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) РеалізаціяТоварівТаПослуг_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(РеалізаціяТоварівТаПослуг_Select.SplitSelectToPages, РеалізаціяТоварівТаПослуг_Select.QuerySelect, unigueIDSelect);

            
            await РеалізаціяТоварівТаПослуг_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (РеалізаціяТоварівТаПослуг_Select.MoveNext())
            {
                Документи.РеалізаціяТоварівТаПослуг_Pointer? curr = РеалізаціяТоварівТаПослуг_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[РеалізаціяТоварівТаПослуг_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[РеалізаціяТоварівТаПослуг_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[РеалізаціяТоварівТаПослуг_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Контрагент", Fields["Контрагент"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("Каса", Fields["Каса"].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("СумаДокументу", Fields[РеалізаціяТоварівТаПослуг_Const.СумаДокументу].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[РеалізаціяТоварівТаПослуг_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
