        public static void CreateFilter(DocumentFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Організація, pointer */
                Switch sw = Switch.New();
                Організації_PointerControl Організація = Організації_PointerControl.New();
                        Організація.Caption = "";
                        Організація.AfterSelectFunc = () => sw.Active = true;
                        object get() => Організація.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ВстановленняЦінНоменклатури_Const.Організація, get, sw));
                form.Filter.Append("Організація:", Організація, sw);
            }
            
            { /* Валюта, pointer */
                Switch sw = Switch.New();
                Валюти_PointerControl Валюта = Валюти_PointerControl.New();
                        Валюта.Caption = "";
                        Валюта.AfterSelectFunc = () => sw.Active = true;
                        object get() => Валюта.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ВстановленняЦінНоменклатури_Const.Валюта, get, sw));
                form.Filter.Append("Валюта:", Валюта, sw);
            }
            
            { /* ВидЦіни, pointer */
                Switch sw = Switch.New();
                ВидиЦін_PointerControl ВидЦіни = ВидиЦін_PointerControl.New();
                        ВидЦіни.Caption = "";
                        ВидЦіни.AfterSelectFunc = () => sw.Active = true;
                        object get() => ВидЦіни.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ВстановленняЦінНоменклатури_Const.ВидЦіни, get, sw));
                form.Filter.Append("Вид ціни:", ВидЦіни, sw);
            }
            
            { /* Автор, pointer */
                Switch sw = Switch.New();
                Користувачі_PointerControl Автор = Користувачі_PointerControl.New();
                        Автор.Caption = "";
                        Автор.AfterSelectFunc = () => sw.Active = true;
                        object get() => Автор.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ВстановленняЦінНоменклатури_Const.Автор, get, sw));
                form.Filter.Append("Автор:", Автор, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DocumentFormJournalBase form)
        {
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Документи.ВстановленняЦінНоменклатури_Select ВстановленняЦінНоменклатури_Select = new();
            ВстановленняЦінНоменклатури_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ВстановленняЦінНоменклатури_Const.Назва,
                    /*НомерДок*/ Документи.ВстановленняЦінНоменклатури_Const.НомерДок,
                    /*ДатаДок*/ Документи.ВстановленняЦінНоменклатури_Const.ДатаДок,
                    /*Коментар*/ Документи.ВстановленняЦінНоменклатури_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ВстановленняЦінНоменклатури_Select.QuerySelect.Order.Add(Документи.ВстановленняЦінНоменклатури_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.Організація,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.Валюта,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_2", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.ВидиЦін_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.ВидЦіни,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_3", "ВидЦіни");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.Автор,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_4", "Автор");
                        

            /* Відбори */
            ВстановленняЦінНоменклатури_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await ВстановленняЦінНоменклатури_Select.Select();
            while (ВстановленняЦінНоменклатури_Select.MoveNext())
            {
                Документи.ВстановленняЦінНоменклатури_Pointer? curr = ВстановленняЦінНоменклатури_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ВстановленняЦінНоменклатури_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ВстановленняЦінНоменклатури_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ВстановленняЦінНоменклатури_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("ВидЦіни", Fields["ВидЦіни"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ВстановленняЦінНоменклатури_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.ВстановленняЦінНоменклатури_Select ВстановленняЦінНоменклатури_Select = new();
            ВстановленняЦінНоменклатури_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ВстановленняЦінНоменклатури_Const.Назва,
                    /*НомерДок*/ Документи.ВстановленняЦінНоменклатури_Const.НомерДок,
                    /*ДатаДок*/ Документи.ВстановленняЦінНоменклатури_Const.ДатаДок,
                    /*Коментар*/ Документи.ВстановленняЦінНоменклатури_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ВстановленняЦінНоменклатури_Select.QuerySelect.Order.Add(Документи.ВстановленняЦінНоменклатури_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.Організація,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.Валюта,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_2", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.ВидиЦін_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.ВидЦіни,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_3", "ВидЦіни");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ВстановленняЦінНоменклатури_Select.QuerySelect, Документи.ВстановленняЦінНоменклатури_Const.Автор,
                            ВстановленняЦінНоменклатури_Select.QuerySelect.Table, "join_tab_4", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) ВстановленняЦінНоменклатури_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.ВстановленняЦінНоменклатури_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ВстановленняЦінНоменклатури_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ВстановленняЦінНоменклатури_Select.SplitSelectToPages, ВстановленняЦінНоменклатури_Select.QuerySelect, unigueIDSelect);

            
            await ВстановленняЦінНоменклатури_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (ВстановленняЦінНоменклатури_Select.MoveNext())
            {
                Документи.ВстановленняЦінНоменклатури_Pointer? curr = ВстановленняЦінНоменклатури_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ВстановленняЦінНоменклатури_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ВстановленняЦінНоменклатури_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ВстановленняЦінНоменклатури_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("ВидЦіни", Fields["ВидЦіни"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ВстановленняЦінНоменклатури_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
