        public static void CreateFilter(DocumentFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Організація, pointer */
                Switch sw = Switch.New();
                Організації_PointerControl Організація = Організації_PointerControl.New();
                        Організація.Caption = "";
                        Організація.AfterSelectFunc = () => sw.Active = true;
                        object get() => Організація.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПрихіднийКасовийОрдер_Const.Організація, get, sw));
                form.Filter.Append("Організація:", Організація, sw);
            }
            
            { /* Валюта, pointer */
                Switch sw = Switch.New();
                Валюти_PointerControl Валюта = Валюти_PointerControl.New();
                        Валюта.Caption = "";
                        Валюта.AfterSelectFunc = () => sw.Active = true;
                        object get() => Валюта.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПрихіднийКасовийОрдер_Const.Валюта, get, sw));
                form.Filter.Append("Валюта:", Валюта, sw);
            }
            
            { /* Каса, pointer */
                Switch sw = Switch.New();
                Каси_PointerControl Каса = Каси_PointerControl.New();
                        Каса.Caption = "";
                        Каса.AfterSelectFunc = () => sw.Active = true;
                        object get() => Каса.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПрихіднийКасовийОрдер_Const.Каса, get, sw));
                form.Filter.Append("Каса:", Каса, sw);
            }
            
            { /* Контрагент, pointer */
                Switch sw = Switch.New();
                Контрагенти_PointerControl Контрагент = Контрагенти_PointerControl.New();
                        Контрагент.Caption = "";
                        Контрагент.AfterSelectFunc = () => sw.Active = true;
                        object get() => Контрагент.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПрихіднийКасовийОрдер_Const.Контрагент, get, sw));
                form.Filter.Append("Контрагент:", Контрагент, sw);
            }
            
            { /* СумаДокументу, numeric */
                Switch sw = Switch.New();
                
                        NumericControl СумаДокументу = NumericControl.New();
                        object get() => СумаДокументу.Value;
                    
                filterList.Add(new(ПрихіднийКасовийОрдер_Const.СумаДокументу, get, sw));
                form.Filter.Append("Сума:", СумаДокументу, sw);
            }
            
            { /* Автор, pointer */
                Switch sw = Switch.New();
                Користувачі_PointerControl Автор = Користувачі_PointerControl.New();
                        Автор.Caption = "";
                        Автор.AfterSelectFunc = () => sw.Active = true;
                        object get() => Автор.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПрихіднийКасовийОрдер_Const.Автор, get, sw));
                form.Filter.Append("Автор:", Автор, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DocumentFormJournalBase form)
        {
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Документи.ПрихіднийКасовийОрдер_Select ПрихіднийКасовийОрдер_Select = new();
            ПрихіднийКасовийОрдер_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ПрихіднийКасовийОрдер_Const.Назва,
                    /*НомерДок*/ Документи.ПрихіднийКасовийОрдер_Const.НомерДок,
                    /*ДатаДок*/ Документи.ПрихіднийКасовийОрдер_Const.ДатаДок,
                    /*СумаДокументу*/ Документи.ПрихіднийКасовийОрдер_Const.СумаДокументу,
                    /*ГосподарськаОперація*/ Документи.ПрихіднийКасовийОрдер_Const.ГосподарськаОперація,
                    /*Коментар*/ Документи.ПрихіднийКасовийОрдер_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ПрихіднийКасовийОрдер_Select.QuerySelect.Order.Add(Документи.ПрихіднийКасовийОрдер_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Організація,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Валюта,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_2", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.Каси_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Каса,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_3", "Каса");
                        
                            /* Приєднання pointer */
                            Довідники.Контрагенти_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Контрагент,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_4", "Контрагент");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Автор,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_5", "Автор");
                        

            /* Відбори */
            ПрихіднийКасовийОрдер_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await ПрихіднийКасовийОрдер_Select.Select();
            while (ПрихіднийКасовийОрдер_Select.MoveNext())
            {
                Документи.ПрихіднийКасовийОрдер_Pointer? curr = ПрихіднийКасовийОрдер_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ПрихіднийКасовийОрдер_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ПрихіднийКасовийОрдер_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ПрихіднийКасовийОрдер_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("Каса", Fields["Каса"].ToString() ?? "");
                    row.Fields.Add("Контрагент", Fields["Контрагент"].ToString() ?? "");
                    row.Fields.Add("СумаДокументу", Fields[ПрихіднийКасовийОрдер_Const.СумаДокументу].ToString() ?? "");
                    row.Fields.Add("ГосподарськаОперація", Перелічення.ПсевдонімиПерелічення.ГосподарськіОперації_Alias((Перелічення.ГосподарськіОперації)(Fields[ПрихіднийКасовийОрдер_Const.ГосподарськаОперація] != DBNull.Value ? Fields[ПрихіднийКасовийОрдер_Const.ГосподарськаОперація] : 0) ));
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ПрихіднийКасовийОрдер_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.ПрихіднийКасовийОрдер_Select ПрихіднийКасовийОрдер_Select = new();
            ПрихіднийКасовийОрдер_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ПрихіднийКасовийОрдер_Const.Назва,
                    /*НомерДок*/ Документи.ПрихіднийКасовийОрдер_Const.НомерДок,
                    /*ДатаДок*/ Документи.ПрихіднийКасовийОрдер_Const.ДатаДок,
                    /*СумаДокументу*/ Документи.ПрихіднийКасовийОрдер_Const.СумаДокументу,
                    /*ГосподарськаОперація*/ Документи.ПрихіднийКасовийОрдер_Const.ГосподарськаОперація,
                    /*Коментар*/ Документи.ПрихіднийКасовийОрдер_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ПрихіднийКасовийОрдер_Select.QuerySelect.Order.Add(Документи.ПрихіднийКасовийОрдер_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Організація,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Валюта,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_2", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.Каси_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Каса,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_3", "Каса");
                        
                            /* Приєднання pointer */
                            Довідники.Контрагенти_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Контрагент,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_4", "Контрагент");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ПрихіднийКасовийОрдер_Select.QuerySelect, Документи.ПрихіднийКасовийОрдер_Const.Автор,
                            ПрихіднийКасовийОрдер_Select.QuerySelect.Table, "join_tab_5", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) ПрихіднийКасовийОрдер_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.ПрихіднийКасовийОрдер_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ПрихіднийКасовийОрдер_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ПрихіднийКасовийОрдер_Select.SplitSelectToPages, ПрихіднийКасовийОрдер_Select.QuerySelect, unigueIDSelect);

            
            await ПрихіднийКасовийОрдер_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (ПрихіднийКасовийОрдер_Select.MoveNext())
            {
                Документи.ПрихіднийКасовийОрдер_Pointer? curr = ПрихіднийКасовийОрдер_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ПрихіднийКасовийОрдер_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ПрихіднийКасовийОрдер_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ПрихіднийКасовийОрдер_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("Каса", Fields["Каса"].ToString() ?? "");
                    row.Fields.Add("Контрагент", Fields["Контрагент"].ToString() ?? "");
                    row.Fields.Add("СумаДокументу", Fields[ПрихіднийКасовийОрдер_Const.СумаДокументу].ToString() ?? "");
                    row.Fields.Add("ГосподарськаОперація", Перелічення.ПсевдонімиПерелічення.ГосподарськіОперації_Alias((Перелічення.ГосподарськіОперації)(Fields[ПрихіднийКасовийОрдер_Const.ГосподарськаОперація] != DBNull.Value ? Fields[ПрихіднийКасовийОрдер_Const.ГосподарськаОперація] : 0) ));
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ПрихіднийКасовийОрдер_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
