        public static void CreateFilter(DocumentFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Організація, pointer */
                Switch sw = Switch.New();
                Організації_PointerControl Організація = Організації_PointerControl.New();
                        Організація.Caption = "";
                        Організація.AfterSelectFunc = () => sw.Active = true;
                        object get() => Організація.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПереміщенняТоварів_Const.Організація, get, sw));
                form.Filter.Append("Організація:", Організація, sw);
            }
            
            { /* СкладВідправник, pointer */
                Switch sw = Switch.New();
                Склади_PointerControl СкладВідправник = Склади_PointerControl.New();
                        СкладВідправник.Caption = "";
                        СкладВідправник.AfterSelectFunc = () => sw.Active = true;
                        object get() => СкладВідправник.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПереміщенняТоварів_Const.СкладВідправник, get, sw));
                form.Filter.Append("Склад відправник:", СкладВідправник, sw);
            }
            
            { /* СкладОтримувач, pointer */
                Switch sw = Switch.New();
                Склади_PointerControl СкладОтримувач = Склади_PointerControl.New();
                        СкладОтримувач.Caption = "";
                        СкладОтримувач.AfterSelectFunc = () => sw.Active = true;
                        object get() => СкладОтримувач.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПереміщенняТоварів_Const.СкладОтримувач, get, sw));
                form.Filter.Append("Склад отримувач:", СкладОтримувач, sw);
            }
            
            { /* Автор, pointer */
                Switch sw = Switch.New();
                Користувачі_PointerControl Автор = Користувачі_PointerControl.New();
                        Автор.Caption = "";
                        Автор.AfterSelectFunc = () => sw.Active = true;
                        object get() => Автор.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПереміщенняТоварів_Const.Автор, get, sw));
                form.Filter.Append("Автор:", Автор, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DocumentFormJournalBase form)
        {
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Документи.ПереміщенняТоварів_Select ПереміщенняТоварів_Select = new();
            ПереміщенняТоварів_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ПереміщенняТоварів_Const.Назва,
                    /*НомерДок*/ Документи.ПереміщенняТоварів_Const.НомерДок,
                    /*ДатаДок*/ Документи.ПереміщенняТоварів_Const.ДатаДок,
                    /*Коментар*/ Документи.ПереміщенняТоварів_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ПереміщенняТоварів_Select.QuerySelect.Order.Add(Документи.ПереміщенняТоварів_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.Організація,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.СкладВідправник,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_2", "СкладВідправник");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.СкладОтримувач,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_3", "СкладОтримувач");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.Автор,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_4", "Автор");
                        

            /* Відбори */
            ПереміщенняТоварів_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await ПереміщенняТоварів_Select.Select();
            while (ПереміщенняТоварів_Select.MoveNext())
            {
                Документи.ПереміщенняТоварів_Pointer? curr = ПереміщенняТоварів_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ПереміщенняТоварів_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ПереміщенняТоварів_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ПереміщенняТоварів_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("СкладВідправник", Fields["СкладВідправник"].ToString() ?? "");
                    row.Fields.Add("СкладОтримувач", Fields["СкладОтримувач"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ПереміщенняТоварів_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.ПереміщенняТоварів_Select ПереміщенняТоварів_Select = new();
            ПереміщенняТоварів_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ПереміщенняТоварів_Const.Назва,
                    /*НомерДок*/ Документи.ПереміщенняТоварів_Const.НомерДок,
                    /*ДатаДок*/ Документи.ПереміщенняТоварів_Const.ДатаДок,
                    /*Коментар*/ Документи.ПереміщенняТоварів_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ПереміщенняТоварів_Select.QuerySelect.Order.Add(Документи.ПереміщенняТоварів_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.Організація,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.СкладВідправник,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_2", "СкладВідправник");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.СкладОтримувач,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_3", "СкладОтримувач");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ПереміщенняТоварів_Select.QuerySelect, Документи.ПереміщенняТоварів_Const.Автор,
                            ПереміщенняТоварів_Select.QuerySelect.Table, "join_tab_4", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) ПереміщенняТоварів_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.ПереміщенняТоварів_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ПереміщенняТоварів_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ПереміщенняТоварів_Select.SplitSelectToPages, ПереміщенняТоварів_Select.QuerySelect, unigueIDSelect);

            
            await ПереміщенняТоварів_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (ПереміщенняТоварів_Select.MoveNext())
            {
                Документи.ПереміщенняТоварів_Pointer? curr = ПереміщенняТоварів_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ПереміщенняТоварів_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ПереміщенняТоварів_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ПереміщенняТоварів_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("СкладВідправник", Fields["СкладВідправник"].ToString() ?? "");
                    row.Fields.Add("СкладОтримувач", Fields["СкладОтримувач"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ПереміщенняТоварів_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
