        public static void CreateFilter(DocumentFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Організація, pointer */
                Switch sw = Switch.New();
                Організації_PointerControl Організація = Організації_PointerControl.New();
                        Організація.Caption = "";
                        Організація.AfterSelectFunc = () => sw.Active = true;
                        object get() => Організація.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПоверненняТоварівВідКлієнта_Const.Організація, get, sw));
                form.Filter.Append("Організація:", Організація, sw);
            }
            
            { /* Валюта, pointer */
                Switch sw = Switch.New();
                Валюти_PointerControl Валюта = Валюти_PointerControl.New();
                        Валюта.Caption = "";
                        Валюта.AfterSelectFunc = () => sw.Active = true;
                        object get() => Валюта.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПоверненняТоварівВідКлієнта_Const.Валюта, get, sw));
                form.Filter.Append("Валюта:", Валюта, sw);
            }
            
            { /* Каса, pointer */
                Switch sw = Switch.New();
                Каси_PointerControl Каса = Каси_PointerControl.New();
                        Каса.Caption = "";
                        Каса.AfterSelectFunc = () => sw.Active = true;
                        object get() => Каса.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПоверненняТоварівВідКлієнта_Const.Каса, get, sw));
                form.Filter.Append("Каса:", Каса, sw);
            }
            
            { /* Контрагент, pointer */
                Switch sw = Switch.New();
                Контрагенти_PointerControl Контрагент = Контрагенти_PointerControl.New();
                        Контрагент.Caption = "";
                        Контрагент.AfterSelectFunc = () => sw.Active = true;
                        object get() => Контрагент.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПоверненняТоварівВідКлієнта_Const.Контрагент, get, sw));
                form.Filter.Append("Контрагент:", Контрагент, sw);
            }
            
            { /* Склад, pointer */
                Switch sw = Switch.New();
                Склади_PointerControl Склад = Склади_PointerControl.New();
                        Склад.Caption = "";
                        Склад.AfterSelectFunc = () => sw.Active = true;
                        object get() => Склад.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПоверненняТоварівВідКлієнта_Const.Склад, get, sw));
                form.Filter.Append("Склад:", Склад, sw);
            }
            
            { /* СумаДокументу, numeric */
                Switch sw = Switch.New();
                
                        NumericControl СумаДокументу = NumericControl.New();
                        object get() => СумаДокументу.Value;
                    
                filterList.Add(new(ПоверненняТоварівВідКлієнта_Const.СумаДокументу, get, sw));
                form.Filter.Append("Сума:", СумаДокументу, sw);
            }
            
            { /* Автор, pointer */
                Switch sw = Switch.New();
                Користувачі_PointerControl Автор = Користувачі_PointerControl.New();
                        Автор.Caption = "";
                        Автор.AfterSelectFunc = () => sw.Active = true;
                        object get() => Автор.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПоверненняТоварівВідКлієнта_Const.Автор, get, sw));
                form.Filter.Append("Автор:", Автор, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DocumentFormJournalBase form)
        {
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Документи.ПоверненняТоварівВідКлієнта_Select ПоверненняТоварівВідКлієнта_Select = new();
            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ПоверненняТоварівВідКлієнта_Const.Назва,
                    /*НомерДок*/ Документи.ПоверненняТоварівВідКлієнта_Const.НомерДок,
                    /*ДатаДок*/ Документи.ПоверненняТоварівВідКлієнта_Const.ДатаДок,
                    /*СумаДокументу*/ Документи.ПоверненняТоварівВідКлієнта_Const.СумаДокументу,
                    /*Коментар*/ Документи.ПоверненняТоварівВідКлієнта_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ПоверненняТоварівВідКлієнта_Select.QuerySelect.Order.Add(Документи.ПоверненняТоварівВідКлієнта_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ПоверненняТоварівВідКлієнта_Select.QuerySelect, Документи.ПоверненняТоварівВідКлієнта_Const.Організація,
                            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Валюти_Pointer.GetJoin(ПоверненняТоварівВідКлієнта_Select.QuerySelect, Документи.ПоверненняТоварівВідКлієнта_Const.Валюта,
                            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Table, "join_tab_2", "Валюта");
                        
                            /* Приєднання pointer */
                            Довідники.Каси_Pointer.GetJoin(ПоверненняТоварівВідКлієнта_Select.QuerySelect, Документи.ПоверненняТоварівВідКлієнта_Const.Каса,
                            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Table, "join_tab_3", "Каса");
                        
                            /* Приєднання pointer */
                            Довідники.Контрагенти_Pointer.GetJoin(ПоверненняТоварівВідКлієнта_Select.QuerySelect, Документи.ПоверненняТоварівВідКлієнта_Const.Контрагент,
                            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Table, "join_tab_4", "Контрагент");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ПоверненняТоварівВідКлієнта_Select.QuerySelect, Документи.ПоверненняТоварівВідКлієнта_Const.Склад,
                            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Table, "join_tab_5", "Склад");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ПоверненняТоварівВідКлієнта_Select.QuerySelect, Документи.ПоверненняТоварівВідКлієнта_Const.Автор,
                            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Table, "join_tab_6", "Автор");
                        

            /* Відбори */
            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await ПоверненняТоварівВідКлієнта_Select.Select();
            while (ПоверненняТоварівВідКлієнта_Select.MoveNext())
            {
                Документи.ПоверненняТоварівВідКлієнта_Pointer? curr = ПоверненняТоварівВідКлієнта_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ПоверненняТоварівВідКлієнта_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ПоверненняТоварівВідКлієнта_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ПоверненняТоварівВідКлієнта_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Валюта", Fields["Валюта"].ToString() ?? "");
                    row.Fields.Add("Каса", Fields["Каса"].ToString() ?? "");
                    row.Fields.Add("Контрагент", Fields["Контрагент"].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("СумаДокументу", Fields[ПоверненняТоварівВідКлієнта_Const.СумаДокументу].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ПоверненняТоварівВідКлієнта_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.ПоверненняТоварівВідКлієнта_Select ПоверненняТоварівВідКлієнта_Select = new();
            ПоверненняТоварівВідКлієнта_Select.QuerySelect.Field.AddRange(
