        public static void CreateFilter(DocumentFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Склад, pointer */
                Switch sw = Switch.New();
                Склади_PointerControl Склад = Склади_PointerControl.New();
                        Склад.Caption = "";
                        Склад.AfterSelectFunc = () => sw.Active = true;
                        object get() => Склад.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПереміщенняТоварівНаСкладі_Const.Склад, get, sw));
                form.Filter.Append("Склад:", Склад, sw);
            }
            
            { /* Організація, pointer */
                Switch sw = Switch.New();
                Організації_PointerControl Організація = Організації_PointerControl.New();
                        Організація.Caption = "";
                        Організація.AfterSelectFunc = () => sw.Active = true;
                        object get() => Організація.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПереміщенняТоварівНаСкладі_Const.Організація, get, sw));
                form.Filter.Append("Організація:", Організація, sw);
            }
            
            { /* Автор, pointer */
                Switch sw = Switch.New();
                Користувачі_PointerControl Автор = Користувачі_PointerControl.New();
                        Автор.Caption = "";
                        Автор.AfterSelectFunc = () => sw.Active = true;
                        object get() => Автор.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПереміщенняТоварівНаСкладі_Const.Автор, get, sw));
                form.Filter.Append("Автор:", Автор, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DocumentFormJournalBase form)
        {
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Документи.ПереміщенняТоварівНаСкладі_Select ПереміщенняТоварівНаСкладі_Select = new();
            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ПереміщенняТоварівНаСкладі_Const.Назва,
                    /*ДатаДок*/ Документи.ПереміщенняТоварівНаСкладі_Const.ДатаДок,
                    /*НомерДок*/ Документи.ПереміщенняТоварівНаСкладі_Const.НомерДок,
                    /*Коментар*/ Документи.ПереміщенняТоварівНаСкладі_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ПереміщенняТоварівНаСкладі_Select.QuerySelect.Order.Add(Документи.ПереміщенняТоварівНаСкладі_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ПереміщенняТоварівНаСкладі_Select.QuerySelect, Документи.ПереміщенняТоварівНаСкладі_Const.Склад,
                            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_1", "Склад");
                        
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ПереміщенняТоварівНаСкладі_Select.QuerySelect, Документи.ПереміщенняТоварівНаСкладі_Const.Організація,
                            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_2", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ПереміщенняТоварівНаСкладі_Select.QuerySelect, Документи.ПереміщенняТоварівНаСкладі_Const.Автор,
                            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_3", "Автор");
                        

            /* Відбори */
            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await ПереміщенняТоварівНаСкладі_Select.Select();
            while (ПереміщенняТоварівНаСкладі_Select.MoveNext())
            {
                Документи.ПереміщенняТоварівНаСкладі_Pointer? curr = ПереміщенняТоварівНаСкладі_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ПереміщенняТоварівНаСкладі_Const.Назва].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ПереміщенняТоварівНаСкладі_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ПереміщенняТоварівНаСкладі_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ПереміщенняТоварівНаСкладі_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.ПереміщенняТоварівНаСкладі_Select ПереміщенняТоварівНаСкладі_Select = new();
            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ПереміщенняТоварівНаСкладі_Const.Назва,
                    /*ДатаДок*/ Документи.ПереміщенняТоварівНаСкладі_Const.ДатаДок,
                    /*НомерДок*/ Документи.ПереміщенняТоварівНаСкладі_Const.НомерДок,
                    /*Коментар*/ Документи.ПереміщенняТоварівНаСкладі_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ПереміщенняТоварівНаСкладі_Select.QuerySelect.Order.Add(Документи.ПереміщенняТоварівНаСкладі_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ПереміщенняТоварівНаСкладі_Select.QuerySelect, Документи.ПереміщенняТоварівНаСкладі_Const.Склад,
                            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_1", "Склад");
                        
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(ПереміщенняТоварівНаСкладі_Select.QuerySelect, Документи.ПереміщенняТоварівНаСкладі_Const.Організація,
                            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_2", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ПереміщенняТоварівНаСкладі_Select.QuerySelect, Документи.ПереміщенняТоварівНаСкладі_Const.Автор,
                            ПереміщенняТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_3", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) ПереміщенняТоварівНаСкладі_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.ПереміщенняТоварівНаСкладі_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ПереміщенняТоварівНаСкладі_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ПереміщенняТоварівНаСкладі_Select.SplitSelectToPages, ПереміщенняТоварівНаСкладі_Select.QuerySelect, unigueIDSelect);

            
            await ПереміщенняТоварівНаСкладі_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (ПереміщенняТоварівНаСкладі_Select.MoveNext())
            {
                Документи.ПереміщенняТоварівНаСкладі_Pointer? curr = ПереміщенняТоварівНаСкладі_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ПереміщенняТоварівНаСкладі_Const.Назва].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ПереміщенняТоварівНаСкладі_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ПереміщенняТоварівНаСкладі_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ПереміщенняТоварівНаСкладі_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
