            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Склад, pointer */
                Switch sw = Switch.New();
                Склади_PointerControl Склад = Склади_PointerControl.New();
                        Склад.Caption = "";
                        Склад.AfterSelectFunc = () => sw.Active = true;
                        object get() => Склад.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЗбіркаТоварівНаСкладі_Const.Склад, get, sw));
                form.Filter.Append("Склад:", Склад, sw);
            }
            
            { /* ДокументРеалізації, pointer */
                Switch sw = Switch.New();
                РеалізаціяТоварівТаПослуг_PointerControl ДокументРеалізації = РеалізаціяТоварівТаПослуг_PointerControl.New();
                        ДокументРеалізації.Caption = "";
                        ДокументРеалізації.AfterSelectFunc = () => sw.Active = true;
                        object get() => ДокументРеалізації.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЗбіркаТоварівНаСкладі_Const.ДокументРеалізації, get, sw));
                form.Filter.Append("Документ реалізації:", ДокументРеалізації, sw);
            }
            
            { /* Автор, pointer */
                Switch sw = Switch.New();
                Користувачі_PointerControl Автор = Користувачі_PointerControl.New();
                        Автор.Caption = "";
                        Автор.AfterSelectFunc = () => sw.Active = true;
                        object get() => Автор.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЗбіркаТоварівНаСкладі_Const.Автор, get, sw));
                form.Filter.Append("Автор:", Автор, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task UpdateRecords(DocumentFormJournalBase form)
        {
            List<ObjectChanged> records = [];
            lock (form.Loсked)
            {
                while(form.RecordsChangedQueue.Count > 0)
                    records.AddRange(form.RecordsChangedQueue.Dequeue());
            }
            
            /* Вибірка */
            Документи.ЗбіркаТоварівНаСкладі_Select ЗбіркаТоварівНаСкладі_Select = new();
            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ЗбіркаТоварівНаСкладі_Const.Назва,
                    /*ДатаДок*/ Документи.ЗбіркаТоварівНаСкладі_Const.ДатаДок,
                    /*НомерДок*/ Документи.ЗбіркаТоварівНаСкладі_Const.НомерДок,
                    /*Коментар*/ Документи.ЗбіркаТоварівНаСкладі_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ЗбіркаТоварівНаСкладі_Select.QuerySelect.Order.Add(Документи.ЗбіркаТоварівНаСкладі_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ЗбіркаТоварівНаСкладі_Select.QuerySelect, Документи.ЗбіркаТоварівНаСкладі_Const.Склад,
                            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_1", "Склад");
                        
                            /* Приєднання pointer */
                            Документи.РеалізаціяТоварівТаПослуг_Pointer.GetJoin(ЗбіркаТоварівНаСкладі_Select.QuerySelect, Документи.ЗбіркаТоварівНаСкладі_Const.ДокументРеалізації,
                            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_2", "ДокументРеалізації");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ЗбіркаТоварівНаСкладі_Select.QuerySelect, Документи.ЗбіркаТоварівНаСкладі_Const.Автор,
                            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_3", "Автор");
                        

            /* Відбори */
            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Where.Add(new Where("uid", Comparison.IN, "'" + string.Join("', '", records.Select(x => x.Uid)) + "'", true));

            
            await ЗбіркаТоварівНаСкладі_Select.Select();
            while (ЗбіркаТоварівНаСкладі_Select.MoveNext())
            {
                Документи.ЗбіркаТоварівНаСкладі_Pointer? curr = ЗбіркаТоварівНаСкладі_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ЗбіркаТоварівНаСкладі_Const.Назва].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ЗбіркаТоварівНаСкладі_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ЗбіркаТоварівНаСкладі_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("ДокументРеалізації", Fields["ДокументРеалізації"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ЗбіркаТоварівНаСкладі_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.ЗбіркаТоварівНаСкладі_Select ЗбіркаТоварівНаСкладі_Select = new();
            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.ЗбіркаТоварівНаСкладі_Const.Назва,
                    /*ДатаДок*/ Документи.ЗбіркаТоварівНаСкладі_Const.ДатаДок,
                    /*НомерДок*/ Документи.ЗбіркаТоварівНаСкладі_Const.НомерДок,
                    /*Коментар*/ Документи.ЗбіркаТоварівНаСкладі_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    ЗбіркаТоварівНаСкладі_Select.QuerySelect.Order.Add(Документи.ЗбіркаТоварівНаСкладі_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(ЗбіркаТоварівНаСкладі_Select.QuerySelect, Документи.ЗбіркаТоварівНаСкладі_Const.Склад,
                            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_1", "Склад");
                        
                            /* Приєднання pointer */
                            Документи.РеалізаціяТоварівТаПослуг_Pointer.GetJoin(ЗбіркаТоварівНаСкладі_Select.QuerySelect, Документи.ЗбіркаТоварівНаСкладі_Const.ДокументРеалізації,
                            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_2", "ДокументРеалізації");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(ЗбіркаТоварівНаСкладі_Select.QuerySelect, Документи.ЗбіркаТоварівНаСкладі_Const.Автор,
                            ЗбіркаТоварівНаСкладі_Select.QuerySelect.Table, "join_tab_3", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) ЗбіркаТоварівНаСкладі_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.ЗбіркаТоварівНаСкладі_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ЗбіркаТоварівНаСкладі_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ЗбіркаТоварівНаСкладі_Select.SplitSelectToPages, ЗбіркаТоварівНаСкладі_Select.QuerySelect, unigueIDSelect);

            
            await ЗбіркаТоварівНаСкладі_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (ЗбіркаТоварівНаСкладі_Select.MoveNext())
            {
                Документи.ЗбіркаТоварівНаСкладі_Pointer? curr = ЗбіркаТоварівНаСкладі_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[ЗбіркаТоварівНаСкладі_Const.Назва].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[ЗбіркаТоварівНаСкладі_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[ЗбіркаТоварівНаСкладі_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("ДокументРеалізації", Fields["ДокументРеалізації"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[ЗбіркаТоварівНаСкладі_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
