                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[РозміщенняНоменклатуриПоКоміркам_Const.Назва].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[РозміщенняНоменклатуриПоКоміркам_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[РозміщенняНоменклатуриПоКоміркам_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[РозміщенняНоменклатуриПоКоміркам_Const.Коментар].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.РозміщенняНоменклатуриПоКоміркам_Select РозміщенняНоменклатуриПоКоміркам_Select = new();
            РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.РозміщенняНоменклатуриПоКоміркам_Const.Назва,
                    /*ДатаДок*/ Документи.РозміщенняНоменклатуриПоКоміркам_Const.ДатаДок,
                    /*НомерДок*/ Документи.РозміщенняНоменклатуриПоКоміркам_Const.НомерДок,
                    /*Коментар*/ Документи.РозміщенняНоменклатуриПоКоміркам_Const.Коментар,
                    
                ]);
            
                    /* Сортування */
                    РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect.Order.Add(Документи.РозміщенняНоменклатуриПоКоміркам_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect, Документи.РозміщенняНоменклатуриПоКоміркам_Const.Організація,
                            РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Склади_Pointer.GetJoin(РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect, Документи.РозміщенняНоменклатуриПоКоміркам_Const.Склад,
                            РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect.Table, "join_tab_2", "Склад");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect, Документи.РозміщенняНоменклатуриПоКоміркам_Const.Автор,
                            РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect.Table, "join_tab_3", "Автор");
                        

            /* Відбори */
            if (form.WhereList != null) РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.РозміщенняНоменклатуриПоКоміркам_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(РозміщенняНоменклатуриПоКоміркам_Select.SplitSelectToPages, РозміщенняНоменклатуриПоКоміркам_Select.QuerySelect, unigueIDSelect);

            
            await РозміщенняНоменклатуриПоКоміркам_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (РозміщенняНоменклатуриПоКоміркам_Select.MoveNext())
            {
                Документи.РозміщенняНоменклатуриПоКоміркам_Pointer? curr = РозміщенняНоменклатуриПоКоміркам_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[РозміщенняНоменклатуриПоКоміркам_Const.Назва].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[РозміщенняНоменклатуриПоКоміркам_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[РозміщенняНоменклатуриПоКоміркам_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Склад", Fields["Склад"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[РозміщенняНоменклатуриПоКоміркам_Const.Коментар].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
