                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[БухгалтерськаОперація_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[БухгалтерськаОперація_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[БухгалтерськаОперація_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[БухгалтерськаОперація_Const.Коментар].ToString() ?? "");
                    row.Fields.Add("Основа", Fields["Основа"].ToString() ?? "");
                    
                    ObjectChanged? objCh = records.Find(x => x.Uid.Equals(curr.UniqueID.UGuid));
                    if (objCh != null)
                    {
                        bool exist = false;
                        for (uint i = 0; i < form.Store.GetNItems(); i++)
                        {
                            DocumentRowJournal? item = (DocumentRowJournal?)form.Store.GetObject(i);
                            if (item != null && item.UniqueID.Equals(curr.UniqueID))
                            {
                                bool sel = form.Grid.Model.IsSelected(i);
                                form.Store.Splice(i, 1, [row], 1);
                                if (sel) form.Grid.Model.SelectItem(i, false);
                                exist = true;
                                break;
                            }
                        }
                        if (!exist && objCh.Type == TypeObjectChanged.Add)
                            form.Store.Append(row);
                    }
                }
            }
        }

        public static async Task LoadRecords(DocumentFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem ?? form.DocumentPointerItem;

            /* Вибірка */
            Документи.БухгалтерськаОперація_Select БухгалтерськаОперація_Select = new();
            БухгалтерськаОперація_Select.QuerySelect.Field.AddRange(
                [
                    "deletion_label",
                    /* + spend */ "spend",
                    /*Назва*/ Документи.БухгалтерськаОперація_Const.Назва,
                    /*НомерДок*/ Документи.БухгалтерськаОперація_Const.НомерДок,
                    /*ДатаДок*/ Документи.БухгалтерськаОперація_Const.ДатаДок,
                    /*Коментар*/ Документи.БухгалтерськаОперація_Const.Коментар,
                    /*Основа*/ Документи.БухгалтерськаОперація_Const.Основа,
                    
                ]);
            
                    /* Сортування */
                    БухгалтерськаОперація_Select.QuerySelect.Order.Add(Документи.БухгалтерськаОперація_Const.ДатаДок, SelectOrder.ASC);
                
                            /* Приєднання pointer */
                            Довідники.Організації_Pointer.GetJoin(БухгалтерськаОперація_Select.QuerySelect, Документи.БухгалтерськаОперація_Const.Організація,
                            БухгалтерськаОперація_Select.QuerySelect.Table, "join_tab_1", "Організація");
                        
                            /* Приєднання pointer */
                            Довідники.Користувачі_Pointer.GetJoin(БухгалтерськаОперація_Select.QuerySelect, Документи.БухгалтерськаОперація_Const.Автор,
                            БухгалтерськаОперація_Select.QuerySelect.Table, "join_tab_2", "Автор");
                        
                            /* Приєднання composite_pointer */
                            БухгалтерськаОперація_Select.QuerySelect.FieldAndAlias.Add(new ValueName<string>($"{SpecialFunc.CompisitePresentation}({Документи.БухгалтерськаОперація_Const.Основа})", "Основа"));
                        

            /* Відбори */
            if (form.WhereList != null) БухгалтерськаОперація_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
             if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod(Документи.БухгалтерськаОперація_Const.ДатаДок, form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) БухгалтерськаОперація_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(БухгалтерськаОперація_Select.SplitSelectToPages, БухгалтерськаОперація_Select.QuerySelect, unigueIDSelect);

            
            await БухгалтерськаОперація_Select.Select();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            while (БухгалтерськаОперація_Select.MoveNext())
            {
                Документи.БухгалтерськаОперація_Pointer? curr = БухгалтерськаОперація_Select.Current;
                if (curr != null)
                {
                    Dictionary<string, object> Fields = curr.Fields;
                    DocumentRowJournal row = DocumentRowJournal.New();
                    row.UniqueID = curr.UniqueID;
                    row.DeletionLabel = (bool)Fields["deletion_label"];
                    row.Spend = (bool)Fields["spend"];
                    row.Fields.Add("Назва", Fields[БухгалтерськаОперація_Const.Назва].ToString() ?? "");
                    row.Fields.Add("НомерДок", Fields[БухгалтерськаОперація_Const.НомерДок].ToString() ?? "");
                    row.Fields.Add("ДатаДок", Fields[БухгалтерськаОперація_Const.ДатаДок].ToString() ?? "");
                    row.Fields.Add("Організація", Fields["Організація"].ToString() ?? "");
                    row.Fields.Add("Автор", Fields["Автор"].ToString() ?? "");
                    row.Fields.Add("Коментар", Fields[БухгалтерськаОперація_Const.Коментар].ToString() ?? "");
                    row.Fields.Add("Основа", Fields["Основа"].ToString() ?? "");
                    
                    form.Store.Append(row);
                    if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
                }
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
        
