        public static void CreateFilter(RegisterInformationFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Номенклатура, pointer */
                Switch sw = Switch.New();
                Номенклатура_PointerControl Номенклатура = Номенклатура_PointerControl.New();
                        Номенклатура.Caption = "";
                        Номенклатура.AfterSelectFunc = () => sw.Active = true;
                        object get() => Номенклатура.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЦіниНоменклатури_Const.Номенклатура, get, sw));
                form.Filter.Append("Номенклатура:", Номенклатура, sw);
            }
            
            { /* ХарактеристикаНоменклатури, pointer */
                Switch sw = Switch.New();
                ХарактеристикиНоменклатури_PointerControl ХарактеристикаНоменклатури = ХарактеристикиНоменклатури_PointerControl.New();
                        ХарактеристикаНоменклатури.Caption = "";
                        ХарактеристикаНоменклатури.AfterSelectFunc = () => sw.Active = true;
                        object get() => ХарактеристикаНоменклатури.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЦіниНоменклатури_Const.ХарактеристикаНоменклатури, get, sw));
                form.Filter.Append("Характеристика:", ХарактеристикаНоменклатури, sw);
            }
            
            { /* ВидЦіни, pointer */
                Switch sw = Switch.New();
                ВидиЦін_PointerControl ВидЦіни = ВидиЦін_PointerControl.New();
                        ВидЦіни.Caption = "";
                        ВидЦіни.AfterSelectFunc = () => sw.Active = true;
                        object get() => ВидЦіни.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЦіниНоменклатури_Const.ВидЦіни, get, sw));
                form.Filter.Append("ВидЦіни:", ВидЦіни, sw);
            }
            
            { /* Ціна, numeric */
                Switch sw = Switch.New();
                
                        NumericControl Ціна = NumericControl.New();
                        object get() => Ціна.Value;
                    
                filterList.Add(new(ЦіниНоменклатури_Const.Ціна, get, sw));
                form.Filter.Append("Ціна:", Ціна, sw);
            }
            
            { /* Пакування, pointer */
                Switch sw = Switch.New();
                ПакуванняОдиниціВиміру_PointerControl Пакування = ПакуванняОдиниціВиміру_PointerControl.New();
                        Пакування.Caption = "";
                        Пакування.AfterSelectFunc = () => sw.Active = true;
                        object get() => Пакування.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЦіниНоменклатури_Const.Пакування, get, sw));
                form.Filter.Append("Пакування:", Пакування, sw);
            }
            
            { /* Валюта, pointer */
                Switch sw = Switch.New();
                Валюти_PointerControl Валюта = Валюти_PointerControl.New();
                        Валюта.Caption = "";
                        Валюта.AfterSelectFunc = () => sw.Active = true;
                        object get() => Валюта.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ЦіниНоменклатури_Const.Валюта, get, sw));
                form.Filter.Append("Валюта:", Валюта, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task LoadRecords(RegisterInformationFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem;

            /* Вибірка */
            РегістриВідомостей.ЦіниНоменклатури_RecordsSet ЦіниНоменклатури_Select = new();
            
                /* Приєднання */
                ЦіниНоменклатури_Select.FillJoin(["period", "owner"]);
            

            /* Відбори */
            if (form.WhereList != null) ЦіниНоменклатури_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
            if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod("period", form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ЦіниНоменклатури_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ЦіниНоменклатури_Select.SplitSelectToPages, ЦіниНоменклатури_Select.QuerySelect, unigueIDSelect);

            
            await ЦіниНоменклатури_Select.Read();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            foreach (ЦіниНоменклатури_RecordsSet.Record record in ЦіниНоменклатури_Select.Records)
            {
                RegisterInformationRowJournal row = RegisterInformationRowJournal.New();
                row.UniqueID = new UniqueID(record.UID);
                row.Period = record.Period;
                row.Owner = record.Owner;
                row.OwnerType = record.OwnerType;
                row.OwnerName = record.OwnerName;
                row.Fields.Add("Номенклатура", record.Номенклатура.Name);
                row.Fields.Add("ХарактеристикаНоменклатури", record.ХарактеристикаНоменклатури.Name);
                row.Fields.Add("ВидЦіни", record.ВидЦіни.Name);
                row.Fields.Add("Ціна", record.Ціна.ToString());
                row.Fields.Add("Пакування", record.Пакування.Name);
                row.Fields.Add("Валюта", record.Валюта.Name);
                
                form.Store.Append(row);
                if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
	    
