        public static void CreateFilter(RegisterAccumulationFormJournalBase form)
        {
            
            List<FilterControl.FilterListItem> filterList = [];
            
            { /* Організація, pointer */
                Switch sw = Switch.New();
                Організації_PointerControl Організація = Організації_PointerControl.New();
                        Організація.Caption = "";
                        Організація.AfterSelectFunc = () => sw.Active = true;
                        object get() => Організація.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПартіїТоварів_Const.Організація, get, sw));
                form.Filter.Append("Організація:", Організація, sw);
            }
            
            { /* ПартіяТоварівКомпозит, pointer */
                Switch sw = Switch.New();
                ПартіяТоварівКомпозит_PointerControl ПартіяТоварівКомпозит = ПартіяТоварівКомпозит_PointerControl.New();
                        ПартіяТоварівКомпозит.Caption = "";
                        ПартіяТоварівКомпозит.AfterSelectFunc = () => sw.Active = true;
                        object get() => ПартіяТоварівКомпозит.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПартіїТоварів_Const.ПартіяТоварівКомпозит, get, sw));
                form.Filter.Append("Партія:", ПартіяТоварівКомпозит, sw);
            }
            
            { /* Номенклатура, pointer */
                Switch sw = Switch.New();
                Номенклатура_PointerControl Номенклатура = Номенклатура_PointerControl.New();
                        Номенклатура.Caption = "";
                        Номенклатура.AfterSelectFunc = () => sw.Active = true;
                        object get() => Номенклатура.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПартіїТоварів_Const.Номенклатура, get, sw));
                form.Filter.Append("Номенклатура:", Номенклатура, sw);
            }
            
            { /* ХарактеристикаНоменклатури, pointer */
                Switch sw = Switch.New();
                ХарактеристикиНоменклатури_PointerControl ХарактеристикаНоменклатури = ХарактеристикиНоменклатури_PointerControl.New();
                        ХарактеристикаНоменклатури.Caption = "";
                        ХарактеристикаНоменклатури.AfterSelectFunc = () => sw.Active = true;
                        object get() => ХарактеристикаНоменклатури.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПартіїТоварів_Const.ХарактеристикаНоменклатури, get, sw));
                form.Filter.Append("Характеристика:", ХарактеристикаНоменклатури, sw);
            }
            
            { /* Серія, pointer */
                Switch sw = Switch.New();
                СеріїНоменклатури_PointerControl Серія = СеріїНоменклатури_PointerControl.New();
                        Серія.Caption = "";
                        Серія.AfterSelectFunc = () => sw.Active = true;
                        object get() => Серія.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПартіїТоварів_Const.Серія, get, sw));
                form.Filter.Append("Серія:", Серія, sw);
            }
            
            { /* Склад, pointer */
                Switch sw = Switch.New();
                Склади_PointerControl Склад = Склади_PointerControl.New();
                        Склад.Caption = "";
                        Склад.AfterSelectFunc = () => sw.Active = true;
                        object get() => Склад.Pointer.UniqueID.UGuid;
                    
                filterList.Add(new(ПартіїТоварів_Const.Склад, get, sw));
                form.Filter.Append("Склад:", Склад, sw);
            }
            
            form.Filter.GetWhere = () =>
            {
                List<Where> where = [];
                foreach (var filter in filterList)
                    if (filter.IsOn.Active)
                        where.Add(new Where(filter.Field, Comparison.EQ, filter.GetValueFunc.Invoke()));

                form.WhereList = where;
                return where.Count != 0;
            };
        
        }

        public static async Task LoadRecords(RegisterAccumulationFormJournalBase form)
        {
            form.BeforeLoadRecords();
            UniqueID? unigueIDSelect = form.SelectPointerItem;

            /* Вибірка */
            РегістриНакопичення.ПартіїТоварів_RecordsSet ПартіїТоварів_Select = new();
            
                /* Приєднання */
                ПартіїТоварів_Select.FillJoin(["period", "owner", "ownerlinenum"]);
            

            /* Відбори */
            if (form.WhereList != null) ПартіїТоварів_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Відбір за період */
            if (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Standart || (form.TypeWhereState == InterfaceGtk4.FormJournal.TypeWhere.Filter && form.Filter.IsUsePeriod))
            {
                Where? where = InterfaceGtk4.PeriodForJournal.SelectionByPeriod("period", form.Period.Period, form.Period.DateStart, form.Period.DateStop);
                if (where != null) ПартіїТоварів_Select.QuerySelect.Where.Add(where);
            }

            /* Cторінки */
            await form.SplitPages(ПартіїТоварів_Select.SplitSelectToPages, ПартіїТоварів_Select.QuerySelect, unigueIDSelect);

            
            await ПартіїТоварів_Select.Read();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            uint selectPosition = 0;
            foreach (ПартіїТоварів_RecordsSet.Record record in ПартіїТоварів_Select.Records)
            {
                RegisterAccumulationRowJournal row = RegisterAccumulationRowJournal.New();
                row.UniqueID = new UniqueID(record.UID);
                row.Income = record.Income;
                row.Period = record.Period;
                row.Owner = record.Owner;
                row.OwnerType = record.OwnerType;
                row.OwnerName = record.OwnerName;
                row.OwnerLineNum = record.OwnerLineNum;
                row.Fields.Add("Організація", record.Організація.Name);
                row.Fields.Add("ПартіяТоварівКомпозит", record.ПартіяТоварівКомпозит.Name);
                row.Fields.Add("Номенклатура", record.Номенклатура.Name);
                row.Fields.Add("ХарактеристикаНоменклатури", record.ХарактеристикаНоменклатури.Name);
                row.Fields.Add("Серія", record.Серія.Name);
                row.Fields.Add("Склад", record.Склад.Name);
                row.Fields.Add("Рядок", record.Рядок.ToString());
                row.Fields.Add("Кількість", record.Кількість.ToString());
                row.Fields.Add("Собівартість", record.Собівартість.ToString());
                row.Fields.Add("СписанаСобівартість", record.СписанаСобівартість.ToString());
                
                form.Store.Append(row);
                if (row.UniqueID.Equals(unigueIDSelect)) selectPosition = form.Store.GetNItems();
            }
            form.AfterLoadRecords(selectPosition);
        }
    }
	    
