        public static async Task LoadRecords(RegisterAccumulationFormJournalSmall form)
        {
            form.BeforeLoadRecords();
            
            /* Вибірка */
            РегістриНакопичення.РухКоштівККМ_RecordsSet РухКоштівККМ_Select = new();
            
                /* Приєднання */
                РухКоштівККМ_Select.FillJoin(["period", "owner", "ownerlinenum"]);
            

            /* Відбори */
            if (form.WhereList != null) РухКоштівККМ_Select.QuerySelect.Where.AddRange(form.WhereList);

            /* Cторінки */
            await form.SplitPages(РухКоштівККМ_Select.SplitSelectToPages, РухКоштівККМ_Select.QuerySelect, null);

            
            await РухКоштівККМ_Select.Read();
            if (form.Store.GetNItems() > 0) form.Store.RemoveAll();
            foreach (РухКоштівККМ_RecordsSet.Record record in РухКоштівККМ_Select.Records)
            {
                RegisterAccumulationRowJournal row = RegisterAccumulationRowJournal.New();
                row.UniqueID = new UniqueID(record.UID);
                row.Income = record.Income;
                row.Period = record.Period;
                row.Owner = record.Owner;
                row.OwnerType = record.OwnerType;
                row.OwnerName = record.OwnerName;
                row.OwnerLineNum = record.OwnerLineNum;
                row.Fields.Add("Організація", record.Організація.Name);
                row.Fields.Add("КасаККМ", record.КасаККМ.Name);
                row.Fields.Add("Валюта", record.Валюта.Name);
                row.Fields.Add("Сума", record.Сума.ToString());
                
                form.Store.Append(row);
            }
            form.AfterLoadRecords(0);
        }
    }
	    
